UPDATE RESERVATIONS
SET user_id         = #{userId},
    reserved_status = 'RESERVED',
    reserved_at     = NOW()
WHERE reservation_id = #{reservationId}
  AND round_id = #{roundId}
  AND seat_id  = #{seatId}
  AND user_id IS NULL

