INSERT INTO RESERVATION_HISTORY (user_id, seat_id, round_id, performance_id, action)
SELECT #{userId}, #{seatId}, #{roundId}, performance_id, #{action}
FROM PERFORMANCE_ROUND
WHERE round_id = #{roundId}
